class Solution:
    def lengthOfLongestSubstring(self, s: str) -> int:
        n = len(s)
        max_len = 0
        # Try every starting position
        for i in range(n):
            # Try every ending position from i
            for j in range(i, n):
                # Check if substring s[i:j+1] has all unique chars
                substring = s[i:j+1]
                if len(substring) == len(set(substring)):
                    max_len = max(max_len, j - i + 1)
                else:
                    # Found a duplicate, no point extending further
                    break
        return max_len

class Solution:
    def lengthOfLongestSubstring(self, s: str) -> int:
        last = {}          # char -> last index seen
        left = 0
        best = 0
        for right, c in enumerate(s):
            if c in last and last[c] >= left:
                left = last[c] + 1
            last[c] = right
            best = max(best, right - left + 1)
        return best

class Solution:
    def minSubArrayLen(self, target: int, nums: List[int]) -> int:
        n = len(nums)
        min_len = float('inf')
        # Try every starting position
        for i in range(n):
            current_sum = 0
            # Try every ending position from i
            for j in range(i, n):
                current_sum += nums[j]
                if current_sum >= target:
                    min_len = min(min_len, j - i + 1)
                    break  # No point extending further from i
        return 0 if min_len == float('inf') else min_len

class Solution:
    def minSubArrayLen(self, target: int, nums: List[int]) -> int:
        left = right = 0
        currentSum, smallestSubArrayLength = 0, 1e9
        while right<len(nums):
            currentSum += nums[right]
            while currentSum>=target:
                smallestSubArrayLength = min(smallestSubArrayLength, right-left+1)
                currentSum -= nums[left]
                left += 1
            right += 1
        return 0 if smallestSubArrayLength==1e9 else smallestSubArrayLength

class Solution:
    def maxProfit(self, prices: List[int]) -> int:
        n = len(prices)
        max_profit = 0
        for i in range(n):
            for j in range(i + 1, n):
                profit = prices[j] - prices[i]
                max_profit = max(max_profit, profit)
        return max_profit

class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        if len(s1) > len(s2):
            return False

        s1_sorted = sorted(s1)
        # Try every window of size len(s1) in s2
        for i in range(len(s2) - len(s1) + 1):
            window = s2[i : i + len(s1)]
            if sorted(window) == s1_sorted:
                return True
        return False

class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        if len(s1) > len(s2):
            return False

        # Count chars in s1 and the first window of s2
        s1_count = {}
        window_count = {}
        for i in range(len(s1)):
            s1_count[s1[i]] = s1_count.get(s1[i], 0) + 1
            window_count[s2[i]] = window_count.get(s2[i], 0) + 1

        # Helper to compare counts
        def matches():
            for c in s1_count:
                if window_count.get(c, 0) != s1_count[c]:
                    return False
            return True

        if matches():
            return True

        # Slide the window
        for right in range(len(s1), len(s2)):
            # Add new char on the right
            window_count[s2[right]] = window_count.get(s2[right], 0) + 1
            # Remove old char on the left
            left = right - len(s1)
            window_count[s2[left]] -= 1
            if window_count[s2[left]] == 0:
                del window_count[s2[left]]

            if matches():
                return True

        return False

class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        if len(s1) > len(s2):
            return False

        s1_count = [0] * 26
        s2_count = [0] * 26

        for i in range(len(s1)):
            s1_count[ord(s1[i]) - ord('a')] += 1
            s2_count[ord(s2[i]) - ord('a')] += 1

        matches = 0
        for i in range(26):
            if s1_count[i] == s2_count[i]:
                matches += 1

        left = 0
        for right in range(len(s1), len(s2)):
            if matches == 26:
                return True

            # Add s2[right]
            idx = ord(s2[right]) - ord('a')
            s2_count[idx] += 1
            if s2_count[idx] == s1_count[idx]:
                matches += 1
            elif s2_count[idx] == s1_count[idx] + 1:
                matches -= 1

            # Remove s2[left]
            idx = ord(s2[left]) - ord('a')
            s2_count[idx] -= 1
            if s2_count[idx] == s1_count[idx]:
                matches += 1
            elif s2_count[idx] == s1_count[idx] - 1:
                matches -= 1

            left += 1

        return matches == 26

class Solution:
    def longestOnes(self, nums, k: int) -> int:
        # window is always the size of max window seen so far with atmost k zeroes
        numZeroesInWindow, sizeOfMaxWindowSeenSoFar = 0, 0

        for index in range(len(nums)):
            if nums[index]==0: 
                numZeroesInWindow += 1
            if numZeroesInWindow>k:
                # if there are more than k zeroes, we slide the window right by one (by removing the left most number in window) 
                # update numZeroesInWindow is applicable... only after we see that in future is there is case where
                # numZeroesInWindow<=k, we are going to increase the size of the window
                # The difference between this and normal sliding window where we pop all elements on left from current window till we see a 0 is that
                # we dont decrease the window size by popping all till left most 0, but we drag along that max window sized window and update 
                # number of zeroes in the window just in case there is a bigger window that we can see in future 
                #    right-left+1 = range = sizeOfWindowWeWant + 1
                # => left = right-sizeOfWindowWeWant
                if nums[index-sizeOfMaxWindowSeenSoFar]==0: numZeroesInWindow -= 1
            else:
                sizeOfMaxWindowSeenSoFar += 1
        return sizeOfMaxWindowSeenSoFar

class Solution:
    def maxVowels(self, s: str, k: int) -> int:
        vowels = "aeiou"
        maxCount = count = sum(char in vowels for char in s[:k])
        left, right = 0, k
        while right<len(s):
            count += ((s[right] in vowels) - (s[left] in vowels))
            left+=1
            right+=1
            maxCount = max(maxCount, count)
        return maxCount

class Solution:
    def maxVowels(self, s: str, k: int) -> int:
        vowels = {"a","e","i","o","u"}
        maxCount = count = sum(char in vowels for char in s[:k])
        for right in range(k, len(s)):
            count += ((s[right] in vowels) - (s[right-k] in vowels))
            maxCount = max(maxCount, count)
        return maxCount

class Solution:
    def findSubstring(self, s: str, words: List[str]) -> List[int]:
        lenOfS, lenOfWords, lenOfEachWord = len(s), len(words), len(words[0])
        wordsSet = set(words)
        wordsInSArr = []
        for index in range(lenOfS-lenOfEachWord+1):
            wordFromIndex = s[index:index+lenOfEachWord]
            wordsInSArr.append(wordFromIndex if wordFromIndex in wordsSet else None)

        counterOfWords = Counter(words)
        indicesWithValidPermutationsArr = []
        for slidingWindowIndex in range(lenOfS-lenOfWords*lenOfEachWord+1):
            currMap = defaultdict(int)
            for loopIndexForEachWord in range(slidingWindowIndex, slidingWindowIndex+lenOfWords*lenOfEachWord+1, lenOfEachWord):
                if loopIndexForEachWord==slidingWindowIndex+lenOfWords*lenOfEachWord: 
                    indicesWithValidPermutationsArr.append(slidingWindowIndex)
                else:
                    if not wordsInSArr[loopIndexForEachWord]: break
                    currMap[wordsInSArr[loopIndexForEachWord]] += 1
                    if currMap[wordsInSArr[loopIndexForEachWord]]>counterOfWords[wordsInSArr[loopIndexForEachWord]]: break
        return indicesWithValidPermutationsArr

