class Solution:
    def findSubstring(self, s: str, words: List[str]) -> List[int]:

        lenOfS, lenOfWord, countOfWords = len(s), len(words[0]), len(words)
        counterOfWords, ansIndices = Counter(words), []

        for left in range(lenOfWord):
            windowWordsFreqMap = defaultdict(int)
            for right in range(left, lenOfS-lenOfWord+1, lenOfWord):
                rightWord = s[right:right+lenOfWord]
                windowWordsFreqMap[rightWord] += 1
                # in case rightWord is not a valid word, we remove everything
                while windowWordsFreqMap[rightWord]>counterOfWords[rightWord]:
                    windowWordsFreqMap[s[left:left+lenOfWord]] -= 1
                    left += lenOfWord
                if left+lenOfWord*countOfWords==right+lenOfWord:
                    ansIndices.append(left)

        return ansIndices

class Solution:
    def minWindow(self, s: str, t: str) -> str:
        if not t or not s:
            return ""

        # Count what we need from t
        need = {}
        for c in t:
            need[c] = need.get(c, 0) + 1

        def is_valid(substring):
            # Check if substring contains all chars of t
            counts = {}
            for c in substring:
                counts[c] = counts.get(c, 0) + 1
            for c in need:
                if counts.get(c, 0) < need[c]:
                    return False
            return True

        min_len = float('inf')
        result = ""
        # Try every starting position
        for i in range(len(s)):
            # Try every ending position from i
            for j in range(i, len(s)):
                substring = s[i:j+1]
                if is_valid(substring):
                    if len(substring) < min_len:
                        min_len = len(substring)
                        result = substring
                    break  # No need to extend further from i

        return result

class Solution:
    def minWindow(self, s: str, t: str) -> str:
        if not t or not s:
            return ""

        # Count chars needed from t
        need = {}
        for c in t:
            need[c] = need.get(c, 0) + 1

        required = len(need)  # number of unique chars in t
        formed = 0  # how many unique chars in window have the correct count

        window_counts = {}
        left = 0
        min_len = float('inf')
        min_left = 0

        for right in range(len(s)):
            c = s[right]
            window_counts[c] = window_counts.get(c, 0) + 1

            # Check if this char's count now matches the need
            if c in need and window_counts[c] == need[c]:
                formed += 1

            # Try to shrink the window while it's valid
            while formed == required and left <= right:
                # Update the result if this window is smaller
                if right - left + 1 < min_len:
                    min_len = right - left + 1
                    min_left = left

                # Remove from the left
                c = s[left]
                window_counts[c] -= 1
                if c in need and window_counts[c] < need[c]:
                    formed -= 1
                left += 1

        return "" if min_len == float('inf') else s[min_left : min_left + min_len]

class Solution:
    def maxSlidingWindow(self, nums: List[int], k: int) -> List[int]:
        result = []
        for i in range(len(nums) - k + 1):
            window_max = max(nums[i : i + k])
            result.append(window_max)
        return result

class Solution:
    def maxSlidingWindow(self, nums: List[int], k: int) -> List[int]:
        from collections import deque
        dq = deque()  # stores indices
        result = []

        for i in range(len(nums)):
            # Remove indices outside the current window
            while dq and dq[0] < i - k + 1:
                dq.popleft()

            # Remove indices of smaller elements (they can't be max)
            while dq and nums[dq[-1]] < nums[i]:
                dq.pop()

            dq.append(i)

            # The window is valid starting at index k-1
            if i >= k - 1:
                result.append(nums[dq[0]])

        return result
